local dialog

local function getChildWindow(window, name, type)
    local child = window:getChildWindow(name, type)
    if not child then
        error("ProbabilityDialog must have" .. name .. " child window.")
    end
    return child
end

local GUIProbabilityDialog = class("GUIProbabilityDialog", IGUILayout)

function GUIProbabilityDialog:onLoad()
    self.curShowType = nil
    local name = string.gsub(self.__name, ".json", "-")
    self.tvTitleText = getChildWindow(self, name .. "Title-Text", GUIType.StaticText)
    self.btnClose = getChildWindow(self, name .. "Close", GUIType.Button)
    self.tvHintText = getChildWindow(self, name .. "Hint-Text", GUIType.StaticText)
    self.llContent = getChildWindow(self, name .. "Content", GUIType.Layout)

    self.btnClose:registerEvent(GUIEvent.ButtonClick, function()
        self:hide()
        SoundUtil.playSound(SoundType.ClosePanel)
    end)

    self.gvList = IGUIGridView.new("ProbabilityDialog-List", self.llContent)
    self.gvList:setConfig(0, 5, 1)
    self.adapter = (require "base.ui.adapter.ProbabilityAdapter").new()
    local itemWidth = self.llContent:GetPixelSize().x
    self.adapter:setItemSize(itemWidth - 1, 57)
    self.gvList:setAdapter(self.adapter)
end

function GUIProbabilityDialog:onShow(type)
    if self.curShowType == type then
        return
    end
    self.curShowType = type
    local setting = GeneralProbability:getSettings(type)
    if not setting then
        self.adapter:setData({})
        return
    end
    self.tvTitleText:SetText(Lang:getString(setting.TitleLang))
    self.tvHintText:SetText(Lang:getString(setting.HintLang))
    self.adapter:setData(setting.List)
end

ProbabilityDialog = {}

function ProbabilityDialog.setItemJsonName(name)
    dialog.adapter:setJsonName(name)
    return ProbabilityDialog
end

function ProbabilityDialog.setListStyle(hSpace, vSpace, column, itemH)
    dialog.gvList:setConfig(hSpace, vSpace, column)
    local itemW = (dialog.llContent:GetPixelSize().x - (hSpace * (column - 1))) / column
    dialog.adapter:setItemSize(itemW - 1, itemH)
    return ProbabilityDialog
end

function ProbabilityDialog.show(type)
    dialog:show(type)
    SoundUtil.playSound(SoundType.OpenPanel)
end

---初始化对话框，可是设置使用的布局json
---@name 对话框的json文件名，默认ProbabilityDialog.json
function initProbabilityDialog(name)
    if dialog ~= nil then
        return
    end
    dialog = GUIProbabilityDialog.new(name)
end

return GUIProbabilityDialog